/**
 * Antigravity UI – Next‑Level Interactions
 * Faizan Ali Portfolio
 */
document.addEventListener('DOMContentLoaded', () => {

  // ---------- Custom Cursor ----------
  const cursor = document.createElement('div');
  cursor.classList.add('custom-cursor');
  document.body.appendChild(cursor);
  document.addEventListener('mousemove', (e) => {
    cursor.style.left = e.clientX + 'px';
    cursor.style.top = e.clientY + 'px';
  });
  // Hover effect on links/buttons
  const hoverElements = document.querySelectorAll('a, button, .ag-btn, input, .ag-card');
  hoverElements.forEach(el => {
    el.addEventListener('mouseenter', () => cursor.classList.add('hover'));
    el.addEventListener('mouseleave', () => cursor.classList.remove('hover'));
  });

  // ---------- Ripple Effect on Buttons ----------
  document.querySelectorAll('.ag-btn, .ag-ripple').forEach(btn => {
    btn.addEventListener('click', function(e) {
      const ripple = document.createElement('span');
      ripple.className = 'ripple-effect';
      const rect = this.getBoundingClientRect();
      const size = Math.max(rect.width, rect.height);
      ripple.style.width = ripple.style.height = size + 'px';
      ripple.style.left = e.clientX - rect.left - size/2 + 'px';
      ripple.style.top = e.clientY - rect.top - size/2 + 'px';
      this.appendChild(ripple);
      ripple.addEventListener('animationend', () => ripple.remove());
    });
  });

  // ---------- Navbar Toggle ----------
  const toggler = document.querySelector('.ag-navbar-toggler');
  const collapse = document.querySelector('.ag-navbar-collapse');
  if (toggler && collapse) {
    toggler.addEventListener('click', () => collapse.classList.toggle('ag-show'));
    const navLinks = collapse.querySelectorAll('.ag-nav-link');
    navLinks.forEach(link => link.addEventListener('click', () => collapse.classList.remove('ag-show')));
  }

  // ---------- Scroll Animations (Intersection Observer) ----------
  const animatedElements = document.querySelectorAll('.ag-animate');
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('ag-fadeInUp'); // Default animation
        // If element has specific class, add corresponding animation
        if (entry.target.classList.contains('ag-slideInLeft')) {
          entry.target.classList.add('ag-slideInLeft-anim');
        }
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.1 });
  animatedElements.forEach(el => observer.observe(el));

  // ---------- Smooth Scroll for Anchor Links (redundant if html smooth scroll, but for older browsers) ----------
  document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
      const target = document.querySelector(this.getAttribute('href'));
      if (target) {
        e.preventDefault();
        target.scrollIntoView({ behavior: 'smooth' });
      }
    });
  });

  // ---------- Back to Top Button ----------
  const backBtn = document.createElement('button');
  backBtn.id = 'back-to-top';
  backBtn.innerHTML = '↑';
  document.body.appendChild(backBtn);
  window.addEventListener('scroll', () => {
    if (window.scrollY > 500) backBtn.style.display = 'flex';
    else backBtn.style.display = 'none';
  });
  backBtn.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));

  // ---------- Navbar Active Link Detection ----------
  const currentPath = window.location.pathname;
  document.querySelectorAll('.ag-nav-link').forEach(link => {
    if (link.getAttribute('href') === currentPath) link.classList.add('active');
  });
});